// Fused RoPE cos/sin embedding generation (SOL-ExecBench problem 012).
//
// reference: emb = cat(freqs, freqs); cos = emb.cos()*scale -> bf16;
//            sin = emb.sin()*scale -> bf16.  Since cos/sin are elementwise and
//            the second half of `emb` duplicates the first, each unique freq
//            produces one (cos,sin) pair written to BOTH halves of the row.
//
// This kernel loads each fp32 freq exactly once (256-bit vectorized loads),
// computes cos+sin with a single accurate `sincosf`, scales, casts to bf16, and
// writes packed 128-bit (uint4 = 8 bf16) stores to both output halves — no
// `cat` intermediate, one kernel launch, one HBM read + two HBM writes.
//
// Why C++/CUDA over the Triton parent: every scored workload is tiny
// (SOL 0.5–3.9us, all data <=27MB) => latency/overhead-bound, not
// bandwidth-bound.  CUPTI times pure on-GPU kernel span, so the lever is a lean
// single-wave kernel body + spreading the work across as many SMs as the shape
// allows.  Grid/block are sized so grid >= ~148 blocks whenever the shape has
// enough work, engaging all memory partitions in one wave.
//
// Numerics: the harness compiles with empty cuda_cflags (NO --use_fast_math),
// so `sincosf` is the accurate device routine — it matches torch.cos/sin to well
// within the bf16 cast and the loose 5% rtol / 0.99 matched-ratio gate.

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <tuple>

#define VEC 8  // freqs processed per thread (half_dim=64 => 8 chunks/row)

__device__ __forceinline__ unsigned pack2(float a, float b) {
    // {a -> low bf16, b -> high bf16} packed into one 32-bit word.
    __nv_bfloat162 p = __floats2bfloat162_rn(a, b);
    return *reinterpret_cast<unsigned*>(&p);
}

// Vectorized path: half_dim is a multiple of VEC (always 64 here).
__global__ void fused_rope_vec_kernel(
        const float* __restrict__ freqs,
        __nv_bfloat16* __restrict__ cos_out,
        __nv_bfloat16* __restrict__ sin_out,
        long n_rows,
        int half_dim,
        int full_dim,
        int chunks_per_row,
        float scale) {
    const long total_chunks = n_rows * (long)chunks_per_row;
    const long stride = (long)gridDim.x * blockDim.x;
    for (long c = (long)blockIdx.x * blockDim.x + threadIdx.x;
         c < total_chunks; c += stride) {
        const long row  = c / chunks_per_row;
        const int  col0 = (int)(c - row * chunks_per_row) * VEC;

        // One 256-bit load (two aligned float4) => 8 fp32 freqs.
        const float4* fp = reinterpret_cast<const float4*>(freqs + row * half_dim + col0);
        float4 a = fp[0];
        float4 b = fp[1];

        float s0, s1, s2, s3, s4, s5, s6, s7;
        float c0, c1, c2, c3, c4, c5, c6, c7;
        sincosf(a.x, &s0, &c0); sincosf(a.y, &s1, &c1);
        sincosf(a.z, &s2, &c2); sincosf(a.w, &s3, &c3);
        sincosf(b.x, &s4, &c4); sincosf(b.y, &s5, &c5);
        sincosf(b.z, &s6, &c6); sincosf(b.w, &s7, &c7);

        uint4 cvec = make_uint4(
            pack2(c0 * scale, c1 * scale), pack2(c2 * scale, c3 * scale),
            pack2(c4 * scale, c5 * scale), pack2(c6 * scale, c7 * scale));
        uint4 svec = make_uint4(
            pack2(s0 * scale, s1 * scale), pack2(s2 * scale, s3 * scale),
            pack2(s4 * scale, s5 * scale), pack2(s6 * scale, s7 * scale));

        __nv_bfloat16* c_lo = cos_out + row * full_dim + col0;
        __nv_bfloat16* s_lo = sin_out + row * full_dim + col0;
        // Replicate cat(freqs,freqs): same value to [col0..] and [col0+half..].
        *reinterpret_cast<uint4*>(c_lo)            = cvec;
        *reinterpret_cast<uint4*>(c_lo + half_dim) = cvec;
        *reinterpret_cast<uint4*>(s_lo)            = svec;
        *reinterpret_cast<uint4*>(s_lo + half_dim) = svec;
    }
}

// Scalar fallback (half_dim not a multiple of VEC — never hit for head_dim=128,
// kept only so an unexpected shape yields a correct result instead of OOB).
__global__ void fused_rope_scalar_kernel(
        const float* __restrict__ freqs,
        __nv_bfloat16* __restrict__ cos_out,
        __nv_bfloat16* __restrict__ sin_out,
        long n_rows, int half_dim, int full_dim, float scale) {
    const long total = n_rows * (long)half_dim;
    const long stride = (long)gridDim.x * blockDim.x;
    for (long i = (long)blockIdx.x * blockDim.x + threadIdx.x; i < total; i += stride) {
        const long row = i / half_dim;
        const int  col = (int)(i - row * half_dim);
        float s, c; sincosf(freqs[i], &s, &c);
        __nv_bfloat16 cb = __float2bfloat16(c * scale);
        __nv_bfloat16 sb = __float2bfloat16(s * scale);
        cos_out[row * full_dim + col]            = cb;
        cos_out[row * full_dim + col + half_dim] = cb;
        sin_out[row * full_dim + col]            = sb;
        sin_out[row * full_dim + col + half_dim] = sb;
    }
}

std::tuple<torch::Tensor, torch::Tensor> run(torch::Tensor freqs, double attention_scaling) {
    freqs = freqs.contiguous();
    TORCH_CHECK(freqs.scalar_type() == torch::kFloat32, "freqs must be float32");
    TORCH_CHECK(freqs.is_cuda(), "freqs must be a CUDA tensor");
    TORCH_CHECK(freqs.dim() >= 1, "freqs must have >=1 dim");

    const int64_t half_dim = freqs.size(-1);
    const int64_t full_dim = half_dim * 2;
    const int64_t n_rows   = (half_dim > 0) ? (freqs.numel() / half_dim) : 0;

    auto out_shape = freqs.sizes().vec();
    out_shape.back() = full_dim;
    auto opts = freqs.options().dtype(torch::kBFloat16);
    torch::Tensor cos = torch::empty(out_shape, opts);
    torch::Tensor sin = torch::empty(out_shape, opts);

    if (n_rows == 0 || half_dim == 0) return std::make_tuple(cos, sin);

    const float scale = static_cast<float>(attention_scaling);
    auto* fptr = freqs.data_ptr<float>();
    auto* cptr = reinterpret_cast<__nv_bfloat16*>(cos.data_ptr());
    auto* sptr = reinterpret_cast<__nv_bfloat16*>(sin.data_ptr());
    cudaStream_t stream = at::cuda::getCurrentCUDAStream().stream();

    const long GRID_CAP = 148L * 64;  // grid-stride handles anything larger

    if (half_dim % VEC == 0) {
        const int  chunks_per_row = (int)(half_dim / VEC);
        const long tc = n_rows * (long)chunks_per_row;
        // Shrink block until grid >= ~148 (spread tiny shapes across all SMs).
        int  block = 256;
        long grid  = (tc + block - 1) / block;
        if (grid < 148) { block = 128; grid = (tc + block - 1) / block; }
        if (grid < 148) { block = 64;  grid = (tc + block - 1) / block; }
        if (grid < 148) { block = 32;  grid = (tc + block - 1) / block; }
        if (grid < 1) grid = 1;
        if (grid > GRID_CAP) grid = GRID_CAP;
        fused_rope_vec_kernel<<<(unsigned)grid, block, 0, stream>>>(
            fptr, cptr, sptr, n_rows, (int)half_dim, (int)full_dim, chunks_per_row, scale);
    } else {
        const long total = n_rows * half_dim;
        int  block = 256;
        long grid  = (total + block - 1) / block;
        if (grid < 148) { block = 64; grid = (total + block - 1) / block; }
        if (grid < 1) grid = 1;
        if (grid > GRID_CAP) grid = GRID_CAP;
        fused_rope_scalar_kernel<<<(unsigned)grid, block, 0, stream>>>(
            fptr, cptr, sptr, n_rows, (int)half_dim, (int)full_dim, scale);
    }
    return std::make_tuple(cos, sin);
}

// Robust scalar marshaling: harness passes attention_scaling as a Python float
// (ScalarInput.value); the Tensor overload is insurance for a 0-d tensor.
std::tuple<torch::Tensor, torch::Tensor> run_tensor_scale(torch::Tensor freqs,
                                                          torch::Tensor scaling) {
    return run(freqs, scaling.item<double>());
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Fused RoPE cos/sin embedding generation (scalar scale)");
    m.def("run", &run_tensor_scale, "Fused RoPE cos/sin embedding generation (tensor scale)");
}
